import { interpolate, useCurrentFrame } from "remotion";

export default function AreaChart() {
  const frame = useCurrentFrame();

  const data = [
    { x: 0, y: 20, label: "Mon" },
    { x: 1, y: 45, label: "Tue" },
    { x: 2, y: 35, label: "Wed" },
    { x: 3, y: 60, label: "Thu" },
    { x: 4, y: 55, label: "Fri" },
    { x: 5, y: 75, label: "Sat" },
    { x: 6, y: 70, label: "Sun" },
    { x: 7, y: 85, label: "Mon" },
    { x: 8, y: 80, label: "Tue" },
    { x: 9, y: 95, label: "Wed" },
  ];

