        style={{
          position: "absolute",
          top: isVertical ? 58 : 46,
          left: isVertical ? 42 : 68,
          right: isVertical ? 42 : 68,
          transform: `translateY(${interpolate(hudProgress, [0, 1], [-18, 0])}px)`,
          zIndex: 50,
        }}
      >
        <div
          style={{
            display: "inline-flex",
            alignItems: "center",
            gap: 12,
            padding: "10px 16px",
            border: "1px solid rgba(34,211,238,0.42)",
            background: "rgba(8,13,24,0.82)",
            clipPath:
              "polygon(0 0, calc(100% - 14px) 0, 100% 14px, 100% 100%, 14px 100%, 0 calc(100% - 14px))",
            boxShadow: "0 0 24px rgba(34,211,238,0.14)",
          }}
        >
          <div
            style={{
              width: 10,
              height: 10,
              background: accentColor,
              boxShadow: `0 0 12px ${accentColor}`,
            }}
          />

          <span
            style={{
              fontSize: isVertical ? 16 : 15,
              letterSpacing: 3,
              color: "rgba(255,255,255,0.78)",
              fontWeight: 800,
              textTransform: "uppercase",
            }}
          >
            {projectCode}
          </span>
        </div>
      </div>

      <div
        style={{
          position: "absolute",
          right: isVertical ? 42 : 68,
          top: isVertical ? 118 : 50,
          padding: "12px 16px",
          border: "1px solid rgba(250,204,21,0.32)",
          background: "rgba(8,13,24,0.76)",
          color: accentColor,
          fontSize: isVertical ? 12 : 14,
          fontWeight: 900,
          letterSpacing: 1.8,
          textTransform: "uppercase",
          clipPath:
            "polygon(0 0, calc(100% - 14px) 0, 100% 14px, 100% 100%, 14px 100%, 0 calc(100% - 14px))",
          boxShadow: "0 0 22px rgba(250,204,21,0.12)",
          opacity: hudProgress,
          zIndex: 50,
        }}
      >
        {statusText}
      </div>

      <div
        style={{
          position: "absolute",
          left: isVertical ? 42 : 68,
          bottom: isVertical ? 56 : 54,
          right: isVertical ? 42 : undefined,
          width: isVertical ? "auto" : 560,
          padding: "18px 20px",
          borderLeft: `3px solid ${accentColor}`,
          background: "rgba(8,13,24,0.82)",
          boxShadow: "0 0 30px rgba(34,211,238,0.08)",
          transform: `translateY(${interpolate(hudProgress, [0, 1], [18, 0])}px)`,
          opacity: hudProgress,
          zIndex: 50,
        }}
      >
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            gap: 18,
            color: "rgba(255,255,255,0.7)",
            fontSize: isVertical ? 16 : 15,
            letterSpacing: 2,
            fontWeight: 750,
            textTransform: "uppercase",
          }}
        >
          <span>{location}</span>
          <span>{progressPercent}% PIP</span>
        </div>

        <div
          style={{
            position: "relative",
            marginTop: 12,
            height: 8,
            width: "100%",
            background: "rgba(255,255,255,0.09)",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              width: `${progressPercent}%`,
              height: "100%",
              background: `linear-gradient(90deg, ${secondaryColor}, ${primaryColor}, ${accentColor})`,
              boxShadow: `0 0 16px ${primaryColor}`,
            }}
          />

          <div
            style={{
              position: "absolute",
              left: `${markerX}%`,
              top: 0,
              bottom: 0,
              width: 3,
              background: accentColor,
              opacity: 0.6,
              boxShadow: `0 0 16px ${accentColor}`,
            }}
          />
        </div>
      </div>

      <CornerBrackets />
    </AbsoluteFill>
  );
}

